<template><div class="workspace-page"><section class="welcome-panel welcome-panel--admin"><div><p>平台账号与机构治理</p><h2>系统运行概览</h2><span>管理员不接触报告、指标、日常测量或健康时间线。</span></div><span class="admin-shield">ADMIN</span></section><section class="metric-grid" v-loading="loading"><article v-for="m in metrics" :key="m.label" class="metric-card"><span class="metric-icon">{{m.icon}}</span><div><small>{{m.label}}</small><strong>{{m.value}}</strong><p>{{m.note}}</p></div></article></section><section class="admin-shortcut-grid"><button v-for="a in actions" :key="a.name" @click="router.push({name:a.name})"><span>{{a.icon}}</span><div><strong>{{a.title}}</strong><small>{{a.note}}</small></div><b>→</b></button></section></div></template><script setup>import{computed,onMounted,ref}from"vue";import{useRouter}from"vue-router";import{fetchAdminDashboard}from"../../api/dashboards";const router=useRouter(),summary=ref({}),loading=ref(false);const metrics=computed(()=>[{label:"全部账号",value:summary.value.account_count||0,icon:"账",note:"不含健康内容"},{label:"普通用户",value:summary.value.regular_user_count||0,icon:"用",note:"可停用或级联删除"},{label:"机构账号",value:summary.value.institution_account_count||0,icon:"机",note:"支持一机构多账号"},{label:"启用机构",value:summary.value.active_institution_count||0,icon:"院",note:`共 ${summary.value.institution_count||0} 家`}]);const actions=[{name:"admin-institutions",icon:"院",title:"机构管理",note:"机构资料、状态和成员"},{name:"admin-invites",icon:"邀",title:"生成下一枚邀请码",note:"明文仅展示一次"},{name:"admin-users",icon:"账",title:"账号管理",note:"停用、恢复和删除"},{name:"admin-comments",icon:"评",title:"评论审核",note:"仅审核公开内容"}];onMounted(async()=>{loading.value=true;try{summary.value=(await fetchAdminDashboard()).data.summary||{}}finally{loading.value=false}});</script>
